import { createHash } from "node:crypto";

/**
 * Fixed namespace UUID (RFC 4122 UUID v5) for deriving Postgres-compatible UUIDs
 * from Firebase Auth UIDs. Same namespace is used for practice, user, and client
 * rows so operators can reproduce values from a UID without calling Firebase.
 */
export const MEMORIES_FIREBASE_CLAIM_NAMESPACE = "c9bdfa20-7a3b-5c8e-a1f2-4d6e8b0c3a91";

function uuidStringToBytes(uuid: string): Buffer {
  const hex = uuid.replace(/-/g, "");
  if (hex.length !== 32) {
    throw new Error("Invalid namespace UUID.");
  }
  return Buffer.from(hex, "hex");
}

function formatUuidFromBytes(bytes: Buffer): string {
  if (bytes.length !== 16) {
    throw new Error("UUID bytes must be length 16.");
  }
  const hex = bytes.toString("hex");
  return `${hex.slice(0, 8)}-${hex.slice(8, 12)}-${hex.slice(12, 16)}-${hex.slice(16, 20)}-${hex.slice(20, 32)}`;
}

export function uuidV5(name: string, namespaceUuid: string = MEMORIES_FIREBASE_CLAIM_NAMESPACE): string {
  const namespaceBytes = uuidStringToBytes(namespaceUuid);
  const digest = createHash("sha1").update(namespaceBytes).update(name, "utf8").digest();
  const bytes = Buffer.from(digest.subarray(0, 16));
  bytes[6] = (bytes[6]! & 0x0f) | 0x50;
  bytes[8] = (bytes[8]! & 0x3f) | 0x80;
  return formatUuidFromBytes(bytes);
}

export function memoriesPracticeIdFromFirebaseUid(firebaseUid: string): string {
  return uuidV5(`practice|${firebaseUid.trim()}`);
}

export function memoriesUserIdFromFirebaseUid(firebaseUid: string): string {
  return uuidV5(`user|${firebaseUid.trim()}`);
}

export function memoriesClientIdFromFirebaseUid(firebaseUid: string): string {
  return uuidV5(`client|${firebaseUid.trim()}`);
}

import { describe, expect, it } from "vitest";
import {
  MEMORIES_FIREBASE_CLAIM_NAMESPACE,
  memoriesClientIdFromFirebaseUid,
  memoriesPracticeIdFromFirebaseUid,
  memoriesUserIdFromFirebaseUid,
  uuidV5,
} from "./firebaseClaimUuids.js";

describe("firebaseClaimUuids", () => {
  it("matches RFC 4122 v5 test vector (DNS namespace + www.example.com)", () => {
    const dnsNamespace = "6ba7b810-9dad-11d1-80b4-00c04fd430c8";
    expect(uuidV5("www.example.com", dnsNamespace)).toBe("21f7c8e8-997b-58e9-9f2d-bb3e4332c4a0");
  });

  it("produces stable Memories tenant UUIDs for a Firebase UID", () => {
    const uid = "firebaseUidExample01";
    expect(memoriesPracticeIdFromFirebaseUid(uid)).toBe(
      uuidV5(`practice|${uid}`, MEMORIES_FIREBASE_CLAIM_NAMESPACE),
    );
    expect(memoriesUserIdFromFirebaseUid(uid)).toBe(uuidV5(`user|${uid}`, MEMORIES_FIREBASE_CLAIM_NAMESPACE));
    expect(memoriesClientIdFromFirebaseUid(uid)).toBe(uuidV5(`client|${uid}`, MEMORIES_FIREBASE_CLAIM_NAMESPACE));
    expect(memoriesPracticeIdFromFirebaseUid(uid)).not.toBe(memoriesUserIdFromFirebaseUid(uid));
  });

  it("trims Firebase UID before hashing", () => {
    expect(memoriesPracticeIdFromFirebaseUid("  abc  ")).toBe(memoriesPracticeIdFromFirebaseUid("abc"));
  });
});

/**
 * Sets Firebase Auth custom claims for Legacy Memories (v0.5 manual onboarding).
 *
 * Prerequisites: Application Default Credentials with permission to edit users
 * (e.g. `gcloud auth application-default login` as a project admin, or a service
 * account key with `roles/firebaseauth.admin`).
 *
 * Usage:
 *   npx tsx scripts/set-memories-firebase-claims.ts <firebase_uid> [--dry-run]
 */
import path from "node:path";
import { fileURLToPath } from "node:url";
import { applicationDefault, initializeApp, getApps } from "firebase-admin/app";
import { getAuth } from "firebase-admin/auth";
import { config as loadEnv } from "dotenv";
import {
  memoriesClientIdFromFirebaseUid,
  memoriesPracticeIdFromFirebaseUid,
  memoriesUserIdFromFirebaseUid,
} from "../src/auth/firebaseClaimUuids.js";

const monorepoRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "../../..");
loadEnv({ path: path.join(monorepoRoot, ".env") });

function parseArgs(argv: string[]): { uid: string; dryRun: boolean } {
  const rest = argv.slice(2).filter((a) => a !== "--");
  const dryRun = argv.includes("--dry-run");
  const uid = rest[0]?.trim();
  if (!uid) {
    console.error("Usage: set-memories-firebase-claims.ts <firebase_uid> [--dry-run]");
    process.exitCode = 1;
    throw new Error("Missing firebase_uid");
  }
  return { uid, dryRun };
}

async function main(): Promise<void> {
  const { uid, dryRun } = parseArgs(process.argv);

  const practiceId = memoriesPracticeIdFromFirebaseUid(uid);
  const userId = memoriesUserIdFromFirebaseUid(uid);
  const clientId = memoriesClientIdFromFirebaseUid(uid);

  const claims = {
    practice_id: practiceId,
    user_id: userId,
    client_id: clientId,
    client_ids: [clientId],
    roles: ["GUIDE"],
  };

  console.log(
    JSON.stringify(
      {
        firebase_uid: uid,
        custom_claims: claims,
        note: "Postgres UUID columns require stable UUIDs; these are UUID v5 derivations of the Firebase UID (see docs/infrastructure.md).",
      },
      null,
      2,
    ),
  );

  if (dryRun) {
    console.log("--dry-run: not calling Firebase Admin.");
    return;
  }

  if (getApps().length === 0) {
    initializeApp({ credential: applicationDefault() });
  }

  await getAuth().setCustomUserClaims(uid, claims);
  console.log("Custom claims written. Ask the user to sign out and sign in again (or wait for token refresh).");
}

main().catch((err: unknown) => {
  console.error(err);
  process.exitCode = 1;
});

