import { useEffect, useState } from "react";
import type { User } from "firebase/auth";
import {
  isFirebaseClientConfigured,
  readMemoriesClaims,
  signOutFirebase,
  subscribeFirebaseUser,
} from "./firebase";

export function useFirebaseSession(): {
  configured: boolean;
  user: User | null;
  loading: boolean;
  defaultClientId: string | null;
  signOut: () => Promise<void>;
} {
  const configured = isFirebaseClientConfigured();
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(configured);
  const [defaultClientId, setDefaultClientId] = useState<string | null>(null);

  useEffect(() => {
    if (!configured) {
      setLoading(false);
      return;
    }

    return subscribeFirebaseUser((next) => {
      void (async () => {
        setUser(next);
        if (!next) {
          setDefaultClientId(null);
          setLoading(false);
          return;
        }
        try {
          const claims = await readMemoriesClaims(next);
          const cid = typeof claims["client_id"] === "string" ? claims["client_id"].trim() : "";
          setDefaultClientId(cid.length > 0 ? cid : null);
        } catch {
          setDefaultClientId(null);
        } finally {
          setLoading(false);
        }
      })();
    });
  }, [configured]);

  return {
    configured,
    user,
    loading,
    defaultClientId,
    signOut: signOutFirebase,
  };
}

