import { afterEach, describe, expect, it, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { RouterProvider } from "@tanstack/react-router";
import { LoginPage } from "./LoginPage";
import { createAppRouter } from "./router";

const signInWithGooglePopup = vi.fn();
const isFirebaseClientConfigured = vi.fn();

vi.mock("../lib/firebase", () => ({
  signInWithGooglePopup,
  isFirebaseClientConfigured,
}));

describe("LoginPage", () => {
  afterEach(() => {
    vi.clearAllMocks();
  });

  it("renders unavailable message when Firebase env is not configured", () => {
    isFirebaseClientConfigured.mockReturnValue(false);
    render(<LoginPage />);
    expect(screen.getByText(/Firebase client keys are missing/i)).toBeInTheDocument();
  });

  it("invokes Google sign-in when the primary button is used", async () => {
    isFirebaseClientConfigured.mockReturnValue(true);
    signInWithGooglePopup.mockResolvedValue(undefined);

    const router = createAppRouter();
    render(
      <RouterProvider router={router} defaultComponent={() => null}>
        <LoginPage />
      </RouterProvider>,
    );

    await userEvent.click(screen.getByRole("button", { name: /Continue with Google/i }));
    expect(signInWithGooglePopup).toHaveBeenCalledTimes(1);
  });
});

